const output = [];

// ---------------------------
// Funções auxiliares
// ---------------------------
function normalizeTelefone(t) {
  if (!t) return null;
  return t.toString().replace(/\D/g, "");
}

function toFloat(v) {
  if (!v) return null;
  return parseFloat(
    String(v)
      .replace(/\./g, "")
      .replace(",", ".")
  );
}

// ---------------------------
// Loop em todos os items
// ---------------------------
for (const item of items) {
  let raw = item.json.content;

  // Parseia o JSON que está dentro do campo "content"
  let i;
  try {
    i = JSON.parse(raw);
  } catch (e) {
    throw new Error("Falha ao fazer JSON.parse do campo 'content'");
  }

  // ---------------------------
  // Telefones
  // ---------------------------
  const telefones = [];

  if (normalizeTelefone(i.telefone1))
    telefones.push({
      telefone: normalizeTelefone(i.telefone1),
      principal: true
    });

  if (normalizeTelefone(i.telefone2))
    telefones.push({
      telefone: normalizeTelefone(i.telefone2)
    });

  if (normalizeTelefone(i.telefone3))
    telefones.push({
      telefone: normalizeTelefone(i.telefone3)
    });

  if (normalizeTelefone(i.telefone4))
    telefones.push({
      telefone: normalizeTelefone(i.telefone4)
    });

  // ---------------------------
  // Produto (id fixo = 5)
  // ---------------------------
  const produto = [
    {
      id_produto: 5,
      valor_ofertado: toFloat(i.valor_ofertado),
      margem_disponivel: toFloat(i.margem_disponivel),
      taxa: toFloat(i.taxa),
      parcela: toFloat(i.parcela),
      prazo: i.prazo ? parseInt(i.prazo) : null
    }
  ];

  // ---------------------------
  // Payload final
  // ---------------------------
  output.push({
    json: {
      p_cpf: i.cpf,
      p_data_nascimento: i.data_nascimento,
      p_id_campanha: i.id_campanha,
      p_nome: i.nome,
      p_origem: "importacao",
      p_perfil_cliente: "INSS_ENTRANTE",
      p_status_atual: "aguardando_contato",
      p_telefones: telefones,
      p_produto: produto
    }
  });
}

return output;
